import styled from "styled-components";

export const Coluna = styled.div`
    display: flex;
    flex-direction: column;
    width: 19%;
    border-radius: 5px;
    background-color: #fec453;
    opacity: 0.85;
    padding: 10px;
    justify-content: start;
    align-items: center;
    font-size: 18px;
`;

export const Titulo = styled.h1`
    font-size: 1.6em;
    font-weight: 600;
`;
